from dataclasses import dataclass


@dataclass
class Order:
    order_id: int
    user: str
    restaurant: str
    items: list

    def to_dict(self):
        return {
            "order_id": self.order_id,
            "user": self.user,
            "restaurant": self.restaurant,
            "items": self.items,
        }

